    this._running = false;
    this._destroyed = false;
    this._visible = true;
    this._clock = 0;
    this._last = 0;
    this._pulse = 0;
    this._mouse = [0.5, 0.5];
    this._target = [0.5, 0.5];
    this._listeners = [];

